/**
 * Componente principal App
 * Commit: Implementação do layout principal com todos os componentes
 */

import React from 'react';
import { IntlProvider } from 'react-intl';
import ptBR from './i18n/locales/pt-BR.json';
import { VehicleProvider } from './contexts/VehicleContext';
import VehicleInfo from './components/VehicleInfo';
import Map from './components/Map';
import RouteSelector from './components/RouteSelector';
import gpsData from '../frontend_data_gps.json';
import './App.scss';

const App = () => {
  const locale = 'pt-BR';
  const messages = ptBR;

  return (
    <IntlProvider locale={locale} messages={messages} defaultLocale="pt-BR">
      <VehicleProvider gpsData={gpsData}>
        <div className="app">
          <header className="app__header">
            <div className="container">
              <h1 className="app__title">
                🚗 Frontend 3D Car - Teste Técnico
              </h1>
            </div>
          </header>

          <main className="app__main">
            <div className="container">
              <div className="app__grid">
                <div className="app__sidebar">
                  <VehicleInfo />
                  <RouteSelector />
                </div>
                
                <div className="app__content">
                  <div className="app__map-wrapper">
                    <Map />
                  </div>
                </div>
              </div>
            </div>
          </main>

          <footer className="app__footer">
            <div className="container">
              <p>
                Projeto desenvolvido com React, Leaflet e SCSS | 
                Dados GPS: Placa {gpsData.vehicle.plate}
              </p>
            </div>
          </footer>
        </div>
      </VehicleProvider>
    </IntlProvider>
  );
};

export default App;
